// Java + Resilience4j semaphore bulkhead example
BulkheadConfig config = BulkheadConfig.custom()
  .maxConcurrentCalls(5)
  .maxWaitDuration(Duration.ofMillis(0)) // fail fast
  .build();
Bulkhead bulkhead = Bulkhead.of("paymentGateway", config);
Supplier<CompletableFuture<OrderResult>> decorated =
  Bulkhead.decorateSupplier(bulkhead, () -> CompletableFuture.supplyAsync(() -> callPaymentGateway()));

try {
  CompletableFuture<OrderResult> future = decorated.get();
  OrderResult r = future.get(2, TimeUnit.SECONDS);
} catch (BulkheadFullException e) {
  // return 429 or fallback behavior
}
